// Find all AAS and their assets to identify transport robots
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset)
RETURN aas.idShort, aas.id, a.globalAssetId, a.assetKind

// Get the AAS ID of MiR100_001
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset {globalAssetId: 'urn:asset:mir100:001'})
RETURN aas.id, aas.idShort

// Find all submodels in the type shell, especially HandoverDocumentation or TechnicalDataAGV
MATCH (type:AssetAdministrationShell {id: 'urn:aas:mir100:type'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN sm.idShort, sm.id

// Check instance shell submodels for current status/error codes
MATCH (aas:AssetAdministrationShell {id: 'urn:aas:mir100:001'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN sm.idShort, sm.id

// Find the AAS for the MiR100 transport robot
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset {globalAssetId: 'urn:asset:mir100:001'})
RETURN aas.id, aas.idShort

// Get the full AAS ID for UR3e_002
MATCH (aas:AssetAdministrationShell {idShort: 'UR3e_002'})
RETURN aas.id AS aasId

// Find all AAS shells and their associated assets to identify the UR3e robot in Hall 4
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(asset:Asset)
RETURN aas.id AS aasId, aas.idShort AS aasIdShort, asset.globalAssetId AS globalAssetId

// Get the AAS ID for UR3e_002
MATCH (aas:AssetAdministrationShell {idShort: 'UR3e_002'})
RETURN aas.id AS aasId

// Find the AAS that manages the asset with globalAssetId "urn:asset:ur3e:002"
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(asset:Asset {globalAssetId: 'urn:asset:ur3e:002'})
RETURN aas.id AS aasId, aas.idShort AS aasIdShort

// Find AAS shells that might be related to UR3e robot in Hall 4
// First, let's look for shells with idShort containing relevant terms
MATCH (aas:AssetAdministrationShell)
RETURN aas.idShort, aas.id
ORDER BY aas.idShort
LIMIT 50

// Check if there's a hierarchical structure connecting UR3e instances to Hall4
MATCH (hall:AssetAdministrationShell {idShort: 'Hall4'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN sm.idShort, sm.id

